const config = $json;
const vehicles = config.vehicles || [];
const cachedVehicles = [];
const needsProcessing = [];

// TEMP_003 skips this, no vehicles required
for (const vehicle of vehicles) {
  const vin = vehicle.vin;

  if (!vin) {
    console.log('Vehicle missing VIN, using original');
    cachedVehicles.push(vehicle);
    continue;
  }

  // Check if bg-removed image exists
  const bgRemovedUrl = `https://res.cloudinary.com/dtpqxuwby/image/upload/${vin}.png`;

  try {
    const response = await this.helpers.httpRequest({
      method: 'HEAD',
      url: bgRemovedUrl,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      timeout: 5000
    });

    if (response.statusCode === 200) {
      console.log(`✓ VIN ${vin}: Found in cache`);
      vehicle.photo_url = bgRemovedUrl;
      cachedVehicles.push(vehicle);
      continue;
    }
  } catch (error) {
    // Not in cache
  }
  needsProcessing.push(vehicle);
}

// Return single item with arrays
return [{
  json: {
    ...config,
    vehicles: vehicles, // ← Now has updated URLs for cached vehicles
    vehiclesToProcess: needsProcessing,
    cachedVehicles: cachedVehicles
  }
}];

// Get all items coming into aggregate
const allItems = $input.all();

// Get base config from Process All Vehicles
const baseConfig = $('Process All Vehicles').first().json;
const cachedVehicles = baseConfig.cachedVehicles || [];
const originalVehicles = baseConfig.vehicles || [];

console.log(`Aggregate: Processing ${allItems.length} items`);

// Process items from removebg/cloudinary flow
const processedVehicles = allItems
  .filter(item => item.json.public_id && item.json.secure_url)
  .map(item => {
    const vin = item.json.public_id;

    // Find the original vehicle data to merge with
    const originalVehicle = originalVehicles.find(v => v.vin === vin);

    if (!originalVehicle) {
      console.warn(`⚠️ No original vehicle found for VIN ${vin}`);
      return null;
    }
    return {
      ...originalVehicle,  // ← Keep all original vehicle data
      photo_url: item.json.secure_url  // ← Add Cloudinary URL
    };
  })
  .filter(Boolean); // Remove any nulls

// Create lookup maps by VIN
const processedByVin = {};
processedVehicles.forEach(v => {
  processedByVin[v.vin] = v;
});

const cachedByVin = {};
cachedVehicles.forEach(v => {
  cachedByVin[v.vin] = v;
});

// Rebuild vehicles array in ORIGINAL order
const finalVehicles = originalVehicles.map(originalVehicle => {
  const vin = originalVehicle.vin;

  // Use processed or cached version if available, otherwise original
  return processedByVin[vin] || cachedByVin[vin] || originalVehicle;
});

console.log(`✓ Total: ${finalVehicles.length} vehicles in correct order`);

// Clean config
const { vehiclesToProcess, cachedVehicles: _, ...cleanConfig } = baseConfig;

return [{
  json: {
    ...cleanConfig,
    vehicles: finalVehicles
  }
}];

// Single error - format it for the email
const error = $input.first().json;
const nodeName = error.node?.name || 'Unknown node';

// Handle different error formats from different APIs
let errorMsg = 'Unknown error';

// Cloudinary error format: { "error": { "message": "..." } }
if (error.error?.message) {
  errorMsg = error.error.message;
}
// Creatomate error format: { "status": "failed", "error_message": "..." }
if (error.error_message) {
  errorMsg = error.error_message;
}

// Remove.bg error format: { "errors": [{ "code": "...", "title": "..." }] }
else if (error.errors && Array.isArray(error.errors) && error.errors.length > 0) {
  const firstError = error.errors[0];
  // Include code if present, otherwise just title
  errorMsg = firstError.code 
    ? `${firstError.code}: ${firstError.title}` 
    : firstError.title;
}
// Creatomate error format: { "error_message": "..." }
else if (error.error_message) {
  errorMsg = error.error_message;
}
// Generic message fallback
else if (error.message) {
  errorMsg = error.message;
}

return [{
  json: {
    nodeName: nodeName,
    errorMessage: errorMsg,
    timestamp: new Date().toISOString(),
    rawError: JSON.stringify(error, null, 2) // Include full error for debugging
  }
}];

const vehiclesToProcess = $json.vehiclesToProcess || [];

return vehiclesToProcess.map(vehicle => ({
  json: vehicle
}));

return [{
  json: $json.api_creatomate_create_video
}]

// hf-render-service /render/{job_id} response shape:
//   { status: "completed", result: { mp4_url, render_ms, ... } }
const apiResponse = $json;
const config       = $('Aggregate Configs').first().json;
const swapBuilt    = $('Build Swap Config').first().json;
const result       = apiResponse && apiResponse.result;
const videoUrl     = result && result.mp4_url;
const videoDuration = swapBuilt._swap_config && swapBuilt._swap_config.videoDuration;

if (!videoUrl) {
  throw new Error('hf-render-service did not return mp4_url (status=' + (apiResponse?.status || 'unknown') + ')');
}

return [{
  json: {
    ...config,
    final_video_url: videoUrl,
    video_duration: videoDuration,
    // Surface _banner_config so [08] Add Platform Banners can read it
    // (computed in Build Swap Config). Null when skipPlatformBanner.
    _banner_config: swapBuilt._banner_config || null,
    ...(config.test_mode && { api_hf_render: apiResponse })
  }
}];

// Get the VIN from context (passed through service)
const vin = $json.context?.vin || $json.vin;

// Get the binary item properly
const binaryData = $input.item.binary?.data;

if (!binaryData) {
  throw new Error('No binary data found');
}

// Return with renamed file and original context data
return {
  json: {
    ...$json.context,
    vin: vin
  },
  binary: {
    data: {
      ...binaryData,
      fileName: `${vin}.png`
    }
  }
};

