const bannerConfig = skipPlatformBanner ? null : {
  text:               callerBannerConfig.text               || platformText,
  font:               callerBannerConfig.font               || (config.brand && config.brand.fontDisplay) || 'Anton',
  text_color:         callerBannerConfig.text_color         || (config.brand && config.brand.accentColor) || '#fe5817',
  bg_color:           callerBannerConfig.bg_color           || (config.brand && config.brand.darkBgColor) || '#022e6d',
  // ffmpeg-banner-api contract: y_percent positions the TOP of the
  // text bounding box; nudging ~30% of band height centers cleanly
  // inside the reserved band. font_size_percent sized at ~50% of band
  // height keeps the type legible without crowding the edges.
  y_percent:          callerBannerConfig.y_percent          != null ? callerBannerConfig.y_percent          : (BANNER_TOP_PCT_F + BANNER_HEIGHT_PCT_F * 0.30) / 100,
  font_size_percent:  callerBannerConfig.font_size_percent  != null ? callerBannerConfig.font_size_percent  : (BANNER_HEIGHT_PCT_F * 0.50) / 100,
  show_background:    false, // the in-render platform-banner-bg already paints the bg
};

// Surface the bg_color into swapConfig so the in-render
// platform-banner-bg pattern paints the same color the ffmpeg text
// pass expects to sit on top of.
if (bannerConfig) {
  swapConfig.platformText = bannerConfig.text;
  swapConfig.bannerBgColor = bannerConfig.bg_color;
}

return [{
  json: {
    ...config,
    _swap_config: Object.fromEntries(Object.entries(swapConfig).filter(([_, v]) => v !== undefined)),
    _stable_id:   stableId,
    _banner_config: bannerConfig,
  }
}];

// Map existing error format to service format
const input = $json;

return [{
  json: {
    workflow_name: "[04] Generate Video",
    error: input.errorMessage || "Unknown error",
    details: input.rawError || JSON.stringify(input, null, 2),
    job_id: null,
    to_email: "errors@ad-pilot.ai"
  }
}];

// Prepare input for Remove Background service
const input = $json;

return {
  json: {
    image_url: input.photo_url || input.image_url,
    size: "auto",
    format: "png",
    crop: true,
    crop_margin: "10%",
    context: {
      vin: input.vin,
      // Pass through other fields needed by Parse Remove.bg
      ...input
    }
  }
};

