// upstream gaps that the per-vehicle data fed.
req('swapConfig.bgImageSource',  swap.bgImageSource);
req('swapConfig.videoDuration',  swap.videoDuration);
req('swapConfig.hookEnd',        swap.hookEnd);
req('swapConfig.ctaStart',       swap.ctaStart);

// Per-visible-vehicle data. Spotlight uses 1 hero + features; multi-
// item uses up to 5. We check every visible item slot the swap built.
const isSpotlight = (cfg.template_id || '').toLowerCase().includes('spotlight');
