const heroVehicle = vehicles[0] || {};

function formatPrice(price) {
  if (price == null || price === '') return '';
  const n = Number(price);
  return Number.isFinite(n) ? `$${n.toLocaleString('en-US')}` : String(price);
}

const bgRendered = config.background_rendered_urls || {};
const bgImageSource = bgRendered[ratio] || bgRendered['9:16'] || null;

const swapConfig = {
  hookEnd:       hookEnd,
  ctaStart:      ctaStart,
  videoDuration: videoDuration,
  skipPlatformBanner,
  platformText,
  bgMusicSource: config.media?.music_url || null,
  bgImageSource,
  bgLightness:   config.bg_lightness || 'mixed',
  avatar1Source:     config.avatar_video_url || null,
  avatar1MaskSource: config.avatar_video_alpha_url || null,
  videoThumbnailText: config.video_thumbnail_text || null,
};

// Per-vehicle fields. Spotlight uses 1 hero + features; multi-item
// uses up to 5 sequential vehicles. The adapter at the render service
// will branch on template_id and consume the appropriate fields.
if (isSpotlight) {
  swapConfig.item1Source  = heroVehicle.photo_url || null;
  swapConfig.item1Title   = heroVehicle.year && heroVehicle.make && heroVehicle.model
    ? `${heroVehicle.year} ${heroVehicle.make} ${heroVehicle.model}`
    : '';
  swapConfig.item1Price   = formatPrice(heroVehicle.price);
  swapConfig.item1Mileage = heroVehicle.mileage
    ? `${Number(heroVehicle.mileage).toLocaleString('en-US')} mi`
    : '';
  // Features 1..4 from feature_photos + segment timings.
  for (let n = 1; n <= 4; n += 1) {
    const photo = (heroVehicle.feature_photos || [])[n - 1];
    const segTiming = sectionTimings.find(t => t.name === `segment_${n}`);
    swapConfig[`item1Feature${n}Source`]   = photo?.photo_url || null;
    swapConfig[`item1Feature${n}Time`]     = segTiming?.start ?? null;
    swapConfig[`item1Feature${n}Duration`] = segTiming?.duration ?? null;
  }
} else {
  for (let i = 1; i <= 5; i += 1) {
    const v = vehicles[i - 1];
    const segTiming = sectionTimings.find(t => t.name === `segment_${i}`);
    if (v) {
      swapConfig[`item${i}Source`]   = v.photo_url || null;
      swapConfig[`item${i}Title`]    = v.year && v.make && v.model
        ? `${v.year} ${v.make} ${v.model}`
        : '';
      swapConfig[`item${i}Price`]    = formatPrice(v.price);
      swapConfig[`item${i}Mileage`]  = v.mileage
        ? `${Number(v.mileage).toLocaleString('en-US')} mi`
        : '';
      swapConfig[`item${i}Time`]     = segTiming?.start ?? null;
      swapConfig[`item${i}Duration`] = segTiming?.duration ?? null;
      swapConfig[`item${i}Visible`]  = true;
    } else {
      swapConfig[`item${i}Visible`] = false;
    }
  }
}

// Stable per-execution id for Cloudinary public_id (alphamerge + duck
// reuse the same id so re-runs overwrite the same asset). Falls back
// to job_id-ratio if no execution_id is available.
const stableId = config.job_id ? `job-${config.job_id}-${ratio.replace(':','x')}` : `hf-render-${Date.now()}`;

// Platform banner config — surfaced for the post-render
// [08] Add Platform Banners step. Position lands the text band
// inside the in-render platform-banner-bg pattern's reserved
// 0-8vh ribbon. ffmpeg-banner-api uses 0-1 floats (y_percent,
// font_size_percent), so we translate from the 0-100 percentages
// our pattern uses.
const BANNER_TOP_PCT_F    = 0;     // band starts at top edge
const BANNER_HEIGHT_PCT_F = 8;     // band height (% of frame height)
const callerBannerConfig = config.bannerConfig || {};
const bannerConfig = skipPlatformBanner ? null : {
  text:               callerBannerConfig.text               || platformText,
  font:               callerBannerConfig.font               || (config.brand && config.brand.fontDisplay) || 'Anton',
  text_color:         callerBannerConfig.text_color         || (config.brand && config.brand.accentColor) || '#fe5817',
  bg_color:           callerBannerConfig.bg_color           || (config.brand && config.brand.darkBgColor) || '#022e6d',
  // ffmpeg-banner-api contract: y_percent positions the TOP of the
  // text bounding box; nudging ~30% of band height centers cleanly
  // inside the reserved band. font_size_percent sized at ~50% of band
  // height keeps the type legible without crowding the edges.
  y_percent:          callerBannerConfig.y_percent          != null ? callerBannerConfig.y_percent          : (BANNER_TOP_PCT_F + BANNER_HEIGHT_PCT_F * 0.30) / 100,
  font_size_percent:  callerBannerConfig.font_size_percent  != null ? callerBannerConfig.font_size_percent  : (BANNER_HEIGHT_PCT_F * 0.50) / 100,
  show_background:    false, // the in-render platform-banner-bg already paints the bg
};

// Surface the bg_color into swapConfig so the in-render
// platform-banner-bg pattern paints the same color the ffmpeg text
// pass expects to sit on top of.
if (bannerConfig) {
  swapConfig.platformText = bannerConfig.text;
  swapConfig.bannerBgColor = bannerConfig.bg_color;
}

return [{
  json: {
    ...config,
    _swap_config: Object.fromEntries(Object.entries(swapConfig).filter(([_, v]) => v !== undefined)),
    _stable_id:   stableId,
    _banner_config: bannerConfig,
  }
}];

// Map existing error format to service format
const input = $json;

return [{
  json: {
    workflow_name: "[04] Generate Video",
    error: input.errorMessage || "Unknown error",
    details: input.rawError || JSON.stringify(input, null, 2),
    job_id: null,
    to_email: "errors@ad-pilot.ai"
  }
}];

// Prepare input for Remove Background service
const input = $json;

return {
  json: {
    image_url: input.photo_url || input.image_url,
    size: "auto",
    format: "png",
    crop: true,
    crop_margin: "10%",
    context: {
      vin: input.vin,
      // Pass through other fields needed by Parse Remove.bg
      ...input
    }
  }
};

