const cfg = $json;
const swap = cfg._swap_config || {};
const errors = [];

function req(label, value) {
  const empty = value == null
    || value === ''
    || (typeof value === 'number' && !Number.isFinite(value))
    || (Array.isArray(value) && value.length === 0);
  if (empty) errors.push(label);
}

// Top-level config required for compositing.
req('avatar_video_url (HeyGen RGB)',        cfg.avatar_video_url);
req('avatar_video_alpha_url (Replicate matte)', cfg.avatar_video_alpha_url);
req('audio_url (TTS VO)',                   cfg.audio_url);
req('media.music_url (bg music)',           cfg.media && cfg.media.music_url);
req('avatar_video_duration',                cfg.avatar_video_duration);
req('_section_timings (hook + cta)',        cfg._section_timings);

// Per-ratio themed bg url.
const ratio = cfg.ratio || '9:16';
const bgs = cfg.background_rendered_urls || {};
req(`background_rendered_urls[${ratio}]`, bgs[ratio]);

// swapConfig sanity — these come out of Build Swap Config and surface
// upstream gaps that the per-vehicle data fed.
req('swapConfig.bgImageSource',  swap.bgImageSource);
req('swapConfig.videoDuration',  swap.videoDuration);
req('swapConfig.hookEnd',        swap.hookEnd);
req('swapConfig.ctaStart',       swap.ctaStart);

// Per-visible-vehicle data. Spotlight uses 1 hero + features; multi-
// item uses up to 5. We check every visible item slot the swap built.
const isSpotlight = (cfg.template_id || '').toLowerCase().includes('spotlight');
const maxItems = isSpotlight ? 1 : 5;
for (let i = 1; i <= maxItems; i += 1) {
  if (swap[`item${i}Visible`] === false) continue;
  if (!swap[`item${i}Source`] && !isSpotlight) continue;
  req(`vehicle ${i} title`,    swap[`item${i}Title`]);
  req(`vehicle ${i} price`,    swap[`item${i}Price`]);
  req(`vehicle ${i} mileage`,  swap[`item${i}Mileage`]);
  req(`vehicle ${i} photo_url`, swap[`item${i}Source`]);
}

if (errors.length) {
  // n8n's Code node surface only shows the first line of a thrown
  // Error's message; pack the missing-field list onto one line so the
  // brief mentions every gap, not just "data missing".
  throw new Error('[04b] Required data missing — render blocked: ' + errors.join('; '));
}
return [{ json: cfg }];
